import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import { WebView } from 'react-native-webview';
import AsyncStorage from '@react-native-async-storage/async-storage';

const CLIENT_ID = 'your_client_id';
const REDIRECT_URI = 'your_redirect_uri';
const AUTH_URL = 'https://your-oauth-server.com/auth';
const TOKEN_URL = 'https://your-oauth-server.com/token';
const SCOPE = 'your_scope';

const App = () => {
  const [authUrl, setAuthUrl] = useState('');
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  useEffect(() => {
    const fetchTokens = async () => {
      const storedAccessToken = await AsyncStorage.getItem('access_token');
      const storedRefreshToken = await AsyncStorage.getItem('refresh_token');
      if (storedAccessToken) {
        setAccessToken(storedAccessToken);
      }
      if (storedRefreshToken) {
        setRefreshToken(storedRefreshToken);
      }
    };
    fetchTokens();
  }, []);

  const initiateAuth = () => {
    const url = `${AUTH_URL}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&scope=${SCOPE}`;
    setAuthUrl(url);
  };

  const handleAuthCode = async (code) => {
    const response = await fetch(TOKEN_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `grant_type=authorization_code&code=${code}&redirect_uri=${REDIRECT_URI}&client_id=${CLIENT_ID}`,
    });
    const data = await response.json();
    if (data.access_token) {
      setAccessToken(data.access_token);
      setRefreshToken(data.refresh_token);
      await AsyncStorage.setItem('access_token', data.access_token);
      await AsyncStorage.setItem('refresh_token', data.refresh_token);
    } else {
      Alert.alert('Error', 'Failed to fetch access token');
    }
  };

  const refreshAccessToken = async () => {
    const response = await fetch(TOKEN_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: `grant_type=refresh_token&refresh_token=${refreshToken}&client_id=${CLIENT_ID}`,
    });
    const data = await response.json();
    if (data.access_token) {
      setAccessToken(data.access_token);
      await AsyncStorage.setItem('access_token', data.access_token);
    } else {
      Alert.alert('Error', 'Failed to refresh access token');
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {accessToken ? (
        <Text>Access Token: {accessToken}</Text>
      ) : (
        <Button title="Login" onPress={initiateAuth} />
      )}
      {authUrl ? (
        <WebView
          source={{ uri: authUrl }}
          onNavigationStateChange={(navState) => {
            if (navState.url.startsWith(REDIRECT_URI)) {
              const code = navState.url.split('code=')[1];
              handleAuthCode(code);
              setAuthUrl('');
            }
          }}
        />
      ) : null}
    </View>
  );
};

export default App;